const currentPassword = String(variables.account_current_password ?? "");
const newPassword = String(variables.account_new_password ?? "");
const confirmPassword = String(variables.account_confirm_password ?? "");

if (!currentPassword) {
  throw new Error("Inserisci la password attuale.");
}

if (newPassword !== confirmPassword) {
  throw new Error("Le nuove password non coincidono.");
}

const checks = [
  newPassword.length >= 12,
  /[a-z]/.test(newPassword),
  /[A-Z]/.test(newPassword),
  /\d/.test(newPassword)
];

if (!checks.every(Boolean)) {
  throw new Error("La nuova password non rispetta i requisiti.");
}

const authPlugin = plugins.supabaseAuth;

if (!authPlugin?.publicInstance) {
  throw new Error("Supabase Auth non è configurato correttamente.");
}

const { data: sessionData, error: sessionError } =
  await authPlugin.publicInstance.auth.getSession();

if (sessionError) {
  throw new Error(sessionError.message);
}

const session = sessionData?.session;

if (!session?.access_token) {
  throw new Error("Utente non autenticato.");
}

const publicData = authPlugin.settings?.publicData ?? {};
const production = publicData.environments?.production ?? {};

const projectUrl =
  production.customDomain ||
  production.projectUrl ||
  publicData.customDomain ||
  publicData.projectUrl;

const apiKey =
  production.apiKey ||
  publicData.apiKey;

if (!projectUrl || !apiKey) {
  throw new Error("Configurazione Supabase incompleta.");
}

const response = await fetch(`${projectUrl}/auth/v1/user`, {
  method: "PUT",
  headers: {
    "Content-Type": "application/json",
    "apikey": apiKey,
    "Authorization": `Bearer ${session.access_token}`
  },
  body: JSON.stringify({
    password: newPassword,
    current_password: currentPassword
  })
});

const result = await response.json().catch(() => ({}));

if (!response.ok) {
  throw new Error(
    result.message ||
    result.msg ||
    "Cambio password non riuscito."
  );
}

if (typeof authPlugin.refreshAuthUser === "function") {
  await authPlugin.refreshAuthUser();
}

return result;

