const getRows = raw => Array.isArray(raw)
  ? raw
  : Array.isArray(raw?.data)
    ? raw.data
    : raw && typeof raw === "object"
      ? Object.values(raw)
      : [];

const escapeHtml = value => String(value ?? "")
  .replace(/&/g, "&amp;")
  .replace(/</g, "&lt;")
  .replace(/>/g, "&gt;")
  .replace(/"/g, "&quot;");

const directImageUrl = raw => {
  const url = String(raw ?? "").trim();
  if (!url) return "";

  const driveFileMatch = url.match(/drive\.google\.com\/file\/d\/([^/]+)/);
  const driveOpenMatch = url.match(/[?&]id=([^&]+)/);
  const driveId = driveFileMatch?.[1] ?? driveOpenMatch?.[1];

  if (driveId) {
    return `https://drive.google.com/thumbnail?id=${driveId}&sz=w1000`;
  }

  const dropboxMatch = url.match(/^https:\/\/www\.dropbox\.com\/(.+)/);
  if (dropboxMatch) {
    return url
      .replace("www.dropbox.com", "dl.dropboxusercontent.com")
      .replace(/[?&]dl=0\b/, "")
      .replace(/[?&]dl=1\b/, "");
  }

  return url;
};

const profile = getRows(collections.profiles?.data)[0] ?? {};

const fallback = "https://cdn.weweb.app/public/images/no_image_selected.png";
const url = directImageUrl(profile.profile_image_url) || fallback;
const zoom = Math.min(Math.max(Number(profile.profile_image_zoom ?? 1), 1), 3);
const x = Math.min(Math.max(Number(profile.profile_image_position_x ?? 50), 0), 100);
const y = Math.min(Math.max(Number(profile.profile_image_position_y ?? 50), 0), 100);

return `
  <div style="
    width: 200px;
    height: 200px;
    overflow: hidden;
    border: 0px solid #A6A6A6;
    border-radius: 1000px;
    background: #1b1925;
  ">
    <img
      src="${escapeHtml(url)}"
      alt=""
      style="
        width: 100%;
        height: 100%;
        display: block;
        object-fit: cover;
        object-position: ${x}% ${y}%;
        transform: scale(${zoom});
        transform-origin: ${x}% ${y}%;
      "
    />
  </div>
`;

